// WS-B (ADR-3S-001): Florida retired. New York + California matrix cells stay.
// Filter keeps source data intact (reversible); FL cells are excluded from every consumer.
export const SERVICE_CITY_PAGES: ServiceCityPage[] = ALL_SERVICE_CITY_PAGES.filter(
  (c) => !c.citySlug.endsWith('-fl'),
);

export function getServiceCityPage(
  citySlug: string,
  serviceSlug: string
): ServiceCityPage | undefined {
  return SERVICE_CITY_PAGES.find(
    (p) => p.citySlug === citySlug && p.serviceSlug === serviceSlug
  );
}
